def ListOptimalTrials(
      self,
      request: vizier_service_pb2.ListOptimalTrialsRequest,
      context: Optional[grpc.ServicerContext] = None,
  ) -> vizier_service_pb2.ListOptimalTrialsResponse:
    """Lists optimal trials for the study."""
    study = self.datastore.load_study(request.parent)
    all_trials = self.datastore.list_trials(request.parent)

    # Filter to trials with final_measurement
    valid_trials = []
    for trial in all_trials:
      if not trial.HasField('final_measurement'):
        continue
      valid_trials.append(trial)

    if not valid_trials:
      return vizier_service_pb2.ListOptimalTrialsResponse(optimal_trials=[])

    metrics = list(study.study_spec.metrics)

    # Single objective case
    if len(metrics) == 1:
      metric_id = metrics[0].metric_id
      goal = metrics[0].goal

      values = []
      for trial in valid_trials:
        for m in trial.final_measurement.metrics:
          if m.metric_id == metric_id:
            values.append(m.value)
            break

      if not values:
        return vizier_service_pb2.ListOptimalTrialsResponse(optimal_trials=[])

      if goal == study_pb2.StudySpec.MetricSpec.MAXIMIZE:
        best_value = max(values)
      else:
        best_value = min(values)

      optimal_trials = []
      for trial in valid_trials:
        for m in trial.final_measurement.metrics:
          if m.metric_id == metric_id and m.value == best_value:
            optimal_trials.append(trial)
            break

      return vizier_service_pb2.ListOptimalTrialsResponse(
          optimal_trials=optimal_trials
      )

    # Multi-objective case: Pareto-optimal
    # First, filter to trials that have all metrics
    complete_trials = []
    for trial in valid_trials:
      metric_ids_in_measurement = set(
          m.metric_id for m in trial.final_measurement.metrics
      )
      if metric_ids_in_measurement == set(m.metric_id for m in metrics):
        complete_trials.append(trial)

    # Compute Pareto-optimal trials
    pareto_optimal = []
    for i, trial_i in enumerate(complete_trials):
      dominated = False
      for j, trial_j in enumerate(complete_trials):
        if i == j:
          continue
        # Check if trial_j dominates trial_i
        better_or_equal = True
        strictly_better = False
        for metric in metrics:
          mid = metric.metric_id
          val_i = None
          val_j = None
          for m in trial_i.final_measurement.metrics:
            if m.metric_id == mid:
              val_i = m.value
              break
          for m in trial_j.final_measurement.metrics:
            if m.metric_id == mid:
              val_j = m.value
              break
          if val_i is None or val_j is None:
            better_or_equal = False
            break
          if metric.goal == study_pb2.StudySpec.MetricSpec.MAXIMIZE:
            if val_j < val_i:
              better_or_equal = False
              break
            if val_j > val_i:
              strictly_better = True
          else:  # MINIMIZE
            if val_j > val_i:
              better_or_equal = False
              break
            if val_j < val_i:
              strictly_better = True
        if better_or_equal and strictly_better:
          dominated = True
          break
      if not dominated:
        pareto_optimal.append(trial_i)

    return vizier_service_pb2.ListOptimalTrialsResponse(
        optimal_trials=pareto_optimal
    )

